# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

local ngx = ngx

local function normalize_path(path)
    local parts = {}
    for part in path:gmatch("[^/]+") do
        if part == ".." then
            if #parts > 0 then
                table.remove(parts)
            else
                return nil
            end
        elseif part ~= "." and part ~= "" then
            parts[#parts + 1] = part
        end
    end
    return table.concat(parts, "/")
end

local function is_valid_filename(name)
    if not name or name == "" then
        return false
    end
    if name:match("%z") then
        return false
    end
    if name:match("^%s") or name:match("%s$") then
        return false
    end
    return true
end

local function resolve_real_path(path)
    local handle = io.popen("realpath -m " .. "'" .. path:gsub("'", "'\\''") .. "' 2>/dev/null")
    if not handle then
        return nil
    end
    local result = handle:read("*a")
    handle:close()
    if result then
        result = result:gsub("%s+$", "")
        if result ~= "" then
            return result
        end
    end
    return nil
end

local function serve_file()
    local args = ngx.req.get_uri_args()
    local filename = args.filename

    if not is_valid_filename(filename) then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Error: Missing or invalid filename parameter.")
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    if filename:match("%z") or filename:match("[\r\n]") then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Error: Filename contains illegal characters.")
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local normalized = normalize_path(filename)
    if not normalized or normalized == "" then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Error: Invalid file path.")
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local base_dir = "./files"

    local base_real = resolve_real_path(base_dir)
    if not base_real then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say("Error: Server configuration error.")
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local target_path = base_dir .. "/" .. normalized
    local target_real = resolve_real_path(target_path)

    if not target_real then
        ngx.status = ngx.HTTP_NOT_FOUND
        ngx.say("Error: File not found.")
        return ngx.exit(ngx.HTTP_NOT_FOUND)
    end

    if target_real:sub(1, #base_real) ~= base_real then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: Access denied.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    if target_real == base_real then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: Access denied.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    local separator = target_real:sub(#base_real + 1, #base_real + 1)
    if separator ~= "/" then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: Access denied.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    local file, err = io.open(target_real, "rb")
    if not file then
        ngx.status = ngx.HTTP_NOT_FOUND
        ngx.say("Error: Unable to open file - " .. (err or "unknown error"))
        return ngx.exit(ngx.HTTP_NOT_FOUND)
    end

    local content = file:read("*a")
    file:close()

    if not content then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say("Error: Unable to read file content.")
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local ext = normalized:match("%.([^%.]+)$")
    local mime_types = {
        html = "text/html",
        htm  = "text/html",
        css  = "text/css",
        js   = "application/javascript",
        json = "application/json",
        xml  = "application/xml",
        txt  = "text/plain",
        csv  = "text/csv",
        png  = "image/png",
        jpg  = "image/jpeg",
        jpeg = "image/jpeg",
        gif  = "image/gif",
        svg  = "image/svg+xml",
        pdf  = "application/pdf",
        zip  = "application/zip",
        gz   = "application/gzip",
    }

    local content_type = "application/octet-stream"
    if ext then
        content_type = mime_types[ext:lower()] or content_type
    end

    ngx.header["Content-Type"] = content_type
    ngx.header["Content-Length"] = #content
    ngx.header["X-Content-Type-Options"] = "nosniff"

    ngx.say(content)
    return ngx.exit(ngx.HTTP_OK)
end

serve_file()